  1	import * as React from 'react';
  2	import { AboutUIModal } from '../../About/AboutUIModal';
  3	import { KialiAppState } from '../../../store/Store';
  4	import { DebugInformation } from '../../../components/DebugInformation/DebugInformation';
  5	import { QuestionCircleIcon } from '@patternfly/react-icons/';
  6	import { connect } from 'react-redux';
  7	import { isUpstream } from '../../UpstreamDetector/UpstreamDetector';
  8	import { Status, StatusKey } from '../../../types/StatusState';
  9	import { config } from '../../../config';
 10	import { Dropdown, DropdownItem, DropdownList, MenuToggle, MenuToggleElement } from '@patternfly/react-core';
 11	import { useKialiTranslation } from 'utils/I18nUtils';
 12	
 13	type ReduxProps = {
 14	  status: Status;
 15	  warningMessages: string[];
 16	};
 17	
 18	type HelpDropdownProps = ReduxProps;
 19	
 20	const HelpDropdownComponent: React.FC<HelpDropdownProps> = (props: HelpDropdownProps) => {
 21	  const [isDropdownOpen, setIsDropdownOpen] = React.useState<boolean>(false);
 22	  const [isAboutModalOpen, setIsAboutModalOpen] = React.useState<boolean>(false);
 23	  const [isDebugInformationOpen, setIsDebugInformationOpen] = React.useState<boolean>(false);
 24	
 25	  const { t } = useKialiTranslation();
 26	
 27	  const onDropdownSelect = (): void => {
 28	    setIsDropdownOpen(!isDropdownOpen);
 29	  };
 30	
 31	  const buildDocumentationLink = (): string => {
 32	    const url = new URL(config.documentation.url);
 33	
 34	    if (isUpstream) {
 35	      const kialiCoreVersion = props.status[StatusKey.KIALI_CORE_VERSION] || 'unknown';
 36	
 37	      url.searchParams.append('utm_source', 'kiali');
 38	      url.searchParams.append('utm_medium', 'app');
 39	      url.searchParams.append('utm_campaign', kialiCoreVersion);
 40	      url.searchParams.append('utm_content', '?-menu');
 41	    }
 42	
 43	    return url.toString();
 44	  };
 45	
 46	  const items: React.ReactNode[] = [];
 47	
 48	  items.push(
 49	    <DropdownItem key={'view_documentation'} onClick={() => window.open(buildDocumentationLink(), '_blank')}>
 50	      Documentation
 51	    </DropdownItem>
 52	  );
 53	
 54	  items.push(
 55	    <DropdownItem key={'view_debug_info'} onClick={() => setIsDebugInformationOpen(true)}>
 56	      View Debug Info
 57	    </DropdownItem>
 58	  );
 59	
 60	  items.push(
 61	    <DropdownItem key={'view_about_info'} onClick={() => setIsAboutModalOpen(true)}>
 62	      About
 63	    </DropdownItem>
 64	  );
 65	
 66	  return (
 67	    <>
 68	      <AboutUIModal
 69	        status={props.status}
 70	        warningMessages={props.warningMessages}
 71	        isOpen={isAboutModalOpen}
 72	        onClose={() => setIsAboutModalOpen(false)}
 73	      />
 74	
 75	      <DebugInformation isOpen={isDebugInformationOpen} onClose={() => setIsDebugInformationOpen(false)} />
 76	
 77	      <Dropdown
 78	        toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
 79	          <MenuToggle
 80	            ref={toggleRef}
 81	            data-test="about-help-button"
 82	            onClick={() => setIsDropdownOpen(!isDropdownOpen)}
 83	            aria-label={t('Help')}
 84	            variant="plain"
 85	            isExpanded={isDropdownOpen}
 86	          >
 87	            <QuestionCircleIcon />
 88	          </MenuToggle>
 89	        )}
 90	        isOpen={isDropdownOpen}
 91	        popperProps={{ position: 'right' }}
 92	        onOpenChange={(isOpen: boolean) => setIsDropdownOpen(isOpen)}
 93	        onSelect={onDropdownSelect}
 94	      >
 95	        <DropdownList>{items}</DropdownList>
 96	      </Dropdown>
 97	    </>
 98	  );
 99	};
100	
101	const mapStateToProps = (state: KialiAppState): ReduxProps => ({
102	  status: state.statusState.status,
103	  warningMessages: state.statusState.warningMessages
104	});
105	
106	export const HelpDropdown = connect(mapStateToProps)(HelpDropdownComponent);

